goal:
修復 ContentView、TabView、以及整體導航流程。

## 問題

1. TabBar 自訂可能在小螢幕上有 Safe Area 問題
2. 各 Tab 內的 NavigationStack 包裝不一致
3. 編輯流程的導航不夠流暢
4. ExportView 和 SettingsView 也需要佈局修復

## ContentView.swift 修復

```swift
struct ContentView: View {
    @State private var selectedTab = 0

    init() {
        // VSCO 風格深色 TabBar
        let appearance = UITabBarAppearance()
        appearance.configureWithOpaqueBackground()
        appearance.backgroundColor = UIColor(PrismColors.background)
        appearance.stackedLayoutAppearance.normal.iconColor = UIColor(PrismColors.textSecondary)
        appearance.stackedLayoutAppearance.selected.iconColor = .white
        appearance.stackedLayoutAppearance.normal.titleTextAttributes = [
            .foregroundColor: UIColor(PrismColors.textSecondary)
        ]
        appearance.stackedLayoutAppearance.selected.titleTextAttributes = [
            .foregroundColor: UIColor.white
        ]
        UITabBar.appearance().standardAppearance = appearance
        UITabBar.appearance().scrollEdgeAppearance = appearance
    }

    var body: some View {
        TabView(selection: $selectedTab) {
            CameraView()
                .tabItem {
                    Label("相機", systemImage: "camera.fill")
                }
                .tag(0)

            NavigationStack {
                GalleryView()
            }
            .tabItem {
                Label("照片庫", systemImage: "photo.on.rectangle")
            }
            .tag(1)

            NavigationStack {
                SettingsView()
            }
            .tabItem {
                Label("設定", systemImage: "gearshape")
            }
            .tag(2)
        }
        .onChange(of: selectedTab) { _, _ in
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
    }
}
```

